svg.script:
        var termtosvg_vars = {
            transforms: [
                {transform: 'translate3D(0, 0px, 0)', easing: 'steps(1, end)'},
{transform: 'translate3D(0, -442px, 0)', easing: 'steps(1, end)', offset: 0.127},
{transform: 'translate3D(0, -884px, 0)', easing: 'steps(1, end)', offset: 0.186},
{transform: 'translate3D(0, -1326px, 0)', easing: 'steps(1, end)', offset: 0.313},
{transform: 'translate3D(0, -1768px, 0)', easing: 'steps(1, end)', offset: 0.440},
{transform: 'translate3D(0, -2210px, 0)', easing: 'steps(1, end)', offset: 0.567},
{transform: 'translate3D(0, -2652px, 0)', easing: 'steps(1, end)', offset: 0.567},
{transform: 'translate3D(0, -3094px, 0)', easing: 'steps(1, end)', offset: 0.633},
{transform: 'translate3D(0, -3536px, 0)', easing: 'steps(1, end)', offset: 0.759},
{transform: 'translate3D(0, -3978px, 0)', easing: 'steps(1, end)', offset: 0.771},
{transform: 'translate3D(0, -4420px, 0)', easing: 'steps(1, end)', offset: 0.862},
{transform: 'translate3D(0, -4420px, 0)', easing: 'steps(1, end)'}
            ],
            timings: {
                duration: 7253,
                iterations: Infinity
            }
        };

var htmlnode = window.frameElement;
var animation = document.getElementById('screen_view').animate(termtosvg_vars.transforms, termtosvg_vars.timings);
var animation_duration = termtosvg_vars.timings.duration;
var term   = document.getElementById('term');
var track = term.getElementById('track');
var ppbutton = term.getElementById('ppbutton');
var play = term.getElementById('play');
var pause = term.getElementById('pause');
var timer = term.getElementById('timer')
var slider_1  = term.getElementById('slider_1');
var intervalHandle = null;
var playing = true;

var trackRect = track.getBoundingClientRect();
var limitLower = parseInt(trackRect.x);
var limitUpper = limitLower + parseInt(trackRect.width);

function update_timer_and_button() {
    var current_time = animation.currentTime % animation_duration;
    var current_position = limitLower + (limitUpper - limitLower) * current_time / animation_duration;
    slider_1.setAttribute('x', parseInt(current_position)+'px');
    timer.textContent = parseInt(current_time / 10) + '/' + parseInt(animation_duration / 10);
}

function setpause() {
    animation.pause();
    play.setAttribute('display', 'inline');
    pause.setAttribute('display', 'none');
    playing = false;
    clearInterval(intervalHandle);
}

function setplay() {
    animation.play();
    play.setAttribute('display', 'none');
    pause.setAttribute('display', 'inline');
    playing = true;
    intervalHandle = setInterval(update_timer_and_button, '100ms');
}

animation.onfinish = setpause;

function togglePlayPause() {
    if (playing) {
      setpause();
    } else {
      setplay();
    }
}

ppbutton.addEventListener('click', togglePlayPause, false)
play.addEventListener('click', togglePlayPause, false)
pause.addEventListener('click', togglePlayPause, false)

function move(evt){
    var pt = term.createSVGPoint();
    pt.x = evt.clientX;
    var cursor_position = pt.matrixTransform(term.getScreenCTM().inverse());
    if ( cursor_position.x < limitLower || cursor_position.x > limitUpper ) {
        return;
    }
    animation.currentTime = animation_duration * (cursor_position.x - limitLower) / (limitUpper - limitLower);
    update_timer_and_button();
};

term.getElementById('wide_track').addEventListener('click', move, false);
term.getElementById('track').addEventListener('click', move, false);

slider_1.addEventListener('mousedown',function(evt){
    var was_playing = playing;
    if (playing) {
        setpause();
    }

    term.addEventListener('mousemove', move, false);
    document.documentElement.addEventListener('mouseup', function(){
            if (was_playing) {
                setplay();
            }
            term.removeEventListener('mousemove', move, false);
    }, false);
}, false);

if (!htmlnode.getAttribute('data-loaded')) {
    var startplay = htmlnode.getAttribute('data-play');
    var display_frame = htmlnode.getAttribute('data-display-frame');
    if (startplay) {
        setplay();
    } else {
        setpause();
    }
    if (display_frame) {
        display_frame=parseInt(display_frame);
        animation.currentTime = display_frame * 10;
    }
    update_timer_and_button();
    htmlnode.setAttribute('data-loaded', 'true');
}
